CREATE TABLE auth.permission_actions (
    id integer NOT NULL,
    calias character varying(50) NOT NULL,
    cname character varying(255) NOT NULL
);

COMMENT ON TABLE auth.permission_actions IS 'RealDictRow({'obj_description': 'Справочник возможных действий над объектами защиты (права)'})';
COMMENT ON COLUMN auth.permission_actions.id IS 'Первичный ключ, уникальный идентификатор действия';
COMMENT ON COLUMN auth.permission_actions.calias IS 'Системный алиас действия (READ, CREATE, UPDATE, DELETE, PRINT, GRANT)';
COMMENT ON COLUMN auth.permission_actions.cname IS 'Человекочитаемое наименование действия';

CREATE TABLE auth.permission_values (
    id integer NOT NULL,
    calias character varying(50) NOT NULL,
    cname character varying(255) NOT NULL
);

COMMENT ON TABLE auth.permission_values IS 'RealDictRow({'obj_description': 'Справочник возможных значений прав (Разрешено, Запрещено, Неопределено)'})';
COMMENT ON COLUMN auth.permission_values.id IS 'Первичный ключ, уникальный идентификатор значения';
COMMENT ON COLUMN auth.permission_values.calias IS 'Системный алиас значения (ALLOW, DENY, UNDEFINED)';
COMMENT ON COLUMN auth.permission_values.cname IS 'Человекочитаемое наименование значения';

CREATE TABLE auth.permissions (
    id bigint NOT NULL,
    role_id integer NOT NULL,
    entity_type_id integer,
    instance_id integer,
    action_id integer NOT NULL,
    value_id integer NOT NULL,
    grantor_id integer,
    tdt_granted timestamp without time zone,
    tdt_expires timestamp without time zone
);

COMMENT ON TABLE auth.permissions IS 'RealDictRow({'obj_description': 'Матрица прав доступа: связь ролей с объектами защиты и действиями'})';
COMMENT ON COLUMN auth.permissions.id IS 'Первичный ключ';
COMMENT ON COLUMN auth.permissions.role_id IS 'Роль, на которую назначается право';
COMMENT ON COLUMN auth.permissions.entity_type_id IS 'Тип сущности (если право на все объекты данного типа)';
COMMENT ON COLUMN auth.permissions.instance_id IS 'Конкретный экземпляр сущности (если право на отдельный объект)';
COMMENT ON COLUMN auth.permissions.action_id IS 'Действие (читать, создавать и т.д.)';
COMMENT ON COLUMN auth.permissions.value_id IS 'Значение (разрешено, запрещено, неопределено)';
COMMENT ON COLUMN auth.permissions.grantor_id IS 'Пользователь, назначивший право';
COMMENT ON COLUMN auth.permissions.tdt_granted IS 'Дата назначения';
COMMENT ON COLUMN auth.permissions.tdt_expires IS 'Дата истечения (если ограничено по времени)';

