CREATE OR REPLACE VIEW ext.rsbu AS
(" SELECT ca.code,\n    ca.cname,\n    ca.account_type,\n    ca.parent_id,\n    ca.is_active,\n    COALESCE(pca.code, 'NULL'::character varying) AS parent_code\n   FROM ext.ext_chart_account ca\n     LEFT JOIN ext.ext_chart_account pca ON pca.id = ca.parent_id\n  WHERE ca.chart_id = (( SELECT entity_instances.id\n           FROM data.entity_instances\n          WHERE entity_instances.id = (( SELECT ext_chart_of_accounts.versionid\n                   FROM ext.ext_chart_of_accounts\n                  WHERE ext_chart_of_accounts.calias::text = 'RAS'::text))))\n  ORDER BY ca.code;",)

CREATE OR REPLACE VIEW ext.v_activeperson AS
(" SELECT i.id AS instanceid,\n    vis.balanceunitid AS ownerbu_id,\n    v.id AS versionid,\n    v.cname AS fullname,\n    p.clastname,\n    p.cfirstname,\n    p.dbirthdate\n   FROM data.entity_instances i\n     JOIN data.entity_visibility vis ON vis.instanceid = i.id\n     JOIN data.entity_versions v ON v.instanceid = i.id\n     JOIN ext.ext_person p ON p.versionid = v.id\n  WHERE v.cversionstatus::text = 'Active'::text AND i.entitytypeid = (( SELECT entitytypes.id\n           FROM meta.entitytypes\n          WHERE entitytypes.calias::text = 'PERSON'::text));",)

