COMMENT ON TABLE lang.translations IS 'RealDictRow({'obj_description': 'Переводы интерфейсных текстов для мультиязычности'})';
COMMENT ON COLUMN lang.translations.id IS 'Первичный ключ';
COMMENT ON COLUMN lang.translations.label_key IS 'Уникальный ключ текста (например, "btn_ok")';
COMMENT ON COLUMN lang.translations.language IS 'Код языка (ru, en, de, zh, tt)';
COMMENT ON COLUMN lang.translations.translation IS 'Текст перевода';
COMMENT ON COLUMN lang.translations.created_at IS 'Дата создания';
COMMENT ON COLUMN lang.translations.updated_at IS 'Дата последнего обновления';

