CREATE TABLE meta.account_aspects (
    id integer NOT NULL,
    account_entitytype_id integer NOT NULL,
    aspect_entitytype_id integer NOT NULL,
    calias character varying(50) NOT NULL,
    cname character varying(255) NOT NULL,
    is_monetary boolean,
    ref_chart_entitytype_id integer
);

COMMENT ON TABLE meta.account_aspects IS 'RealDictRow({'obj_description': 'Связка типа счёта с типом ипостаси: определяет, какие ипостаси доступны для данного счёта'})';
COMMENT ON COLUMN meta.account_aspects.id IS 'Первичный ключ';
COMMENT ON COLUMN meta.account_aspects.account_entitytype_id IS 'Тип сущности "Счёт" (ссылка на meta.entitytypes)';
COMMENT ON COLUMN meta.account_aspects.aspect_entitytype_id IS 'Тип сущности "Ипостась" (ссылка на meta.entitytypes)';
COMMENT ON COLUMN meta.account_aspects.calias IS 'Код ипостаси в рамках счёта (например, QTY, SUM)';
COMMENT ON COLUMN meta.account_aspects.cname IS 'Наименование ипостаси (например, "Количество", "Стоимость")';
COMMENT ON COLUMN meta.account_aspects.is_monetary IS 'Признак денежной ипостаси: если true, то привязывается к плану счетов';
COMMENT ON COLUMN meta.account_aspects.ref_chart_entitytype_id IS 'Для денежных ипостасей – тип плана счетов, к которому привязывается';

CREATE TABLE meta.calculations (
    id integer NOT NULL,
    calias character varying(100) NOT NULL,
    cfilepath text NOT NULL,
    chash character(64),
    tlastupdate timestamp without time zone
);

COMMENT ON TABLE meta.calculations IS 'RealDictRow({'obj_description': 'Хранилище метаданных внешних расчётов/алгоритмов (не являются сущностями). Содержит пути к исполняемым процедурам или скриптам.'})';
COMMENT ON COLUMN meta.calculations.id IS 'Первичный ключ';
COMMENT ON COLUMN meta.calculations.calias IS 'Системный код расчёта (уникальный)';
COMMENT ON COLUMN meta.calculations.cfilepath IS 'Путь к файлу с исполняемым кодом (скрипт, процедура)';
COMMENT ON COLUMN meta.calculations.chash IS 'Хеш-сумма файла для контроля целостности (опционально)';
COMMENT ON COLUMN meta.calculations.tlastupdate IS 'Дата и время последнего обновления записи';

CREATE TABLE meta.class_composition_templates (
