    isortorder integer NOT NULL,
    is_required boolean NOT NULL,
    mcomment text
);

COMMENT ON TABLE meta.class_composition_templates IS 'RealDictRow({'obj_description': 'Шаблоны дочерних таблиц для классов сущностей. При создании новой сущности указанного класса эти связи создаются автоматически.'})';

CREATE TABLE meta.class_field_templates (
    id integer NOT NULL,
    class_id integer NOT NULL,
    field_name character varying(63) NOT NULL,
    field_type character(1) NOT NULL,
    calias character varying(255) NOT NULL,
    nlength integer,
    is_indexed boolean,
    is_required boolean,
    ref_entitytype_id integer,
    sort_order integer,
    is_system boolean,
    ref_class_id integer
);

COMMENT ON TABLE meta.class_field_templates IS 'RealDictRow({'obj_description': None})';
COMMENT ON COLUMN meta.class_field_templates.ref_class_id IS 'Ссылка на класс сущности (если не указана конкретная сущность)';

CREATE TABLE meta.composition_roles (
    id integer NOT NULL,
    calias character varying(50) NOT NULL,
    cname character varying(255) NOT NULL,
    mcomment text
);

COMMENT ON TABLE meta.composition_roles IS 'RealDictRow({'obj_description': 'Справочник ролей подчинённых таблиц (вложений). Определяет смысл связи «мастер-деталь» (например, «Спецификация», «Бонусы», «Файлы»).'})';
COMMENT ON COLUMN meta.composition_roles.id IS 'Первичный ключ';
COMMENT ON COLUMN meta.composition_roles.calias IS 'Системный алиас роли (например, ROLE_ITEMS, ROLE_BONUS)';
COMMENT ON COLUMN meta.composition_roles.cname IS 'Человеческое название роли';
COMMENT ON COLUMN meta.composition_roles.mcomment IS 'Описание роли, её назначение';

