    current_year integer
);

COMMENT ON TABLE meta.doc_numberers IS 'RealDictRow({'obj_description': 'Нумераторы документов по типам и БЕ'})';

CREATE TABLE meta.doc_route_bindings (
    id integer NOT NULL,
    entitytype_id integer NOT NULL,
