    balanceunit_id integer NOT NULL,
    is_default boolean NOT NULL,
    is_active boolean NOT NULL,
    mcomment text
);

COMMENT ON TABLE meta.doc_route_bindings IS 'RealDictRow({'obj_description': 'Связь типов документов с шаблонами маршрутов в рамках БЕ'})';

CREATE TABLE meta.doc_settings (
    id integer NOT NULL,
    balanceunit_id integer,
    setting_key character varying(100) NOT NULL,
    setting_value text,
    description text
);

COMMENT ON TABLE meta.doc_settings IS 'RealDictRow({'obj_description': 'Настройки документооборота (глобальные и для каждой БЕ)'})';

CREATE TABLE meta.entity_classes (
    id integer NOT NULL,
    calias character varying(50) NOT NULL,
    cname character varying(255) NOT NULL,
    mcomment text
);

COMMENT ON TABLE meta.entity_classes IS 'RealDictRow({'obj_description': 'Справочник классов (типов) сущностей, определяющий поведение объектов в системе'})';
COMMENT ON COLUMN meta.entity_classes.id IS 'Первичный ключ, уникальный идентификатор класса';
COMMENT ON COLUMN meta.entity_classes.calias IS 'Системный алиас класса, используется в коде (например, DICT, DOC, ACCOUNT)';
COMMENT ON COLUMN meta.entity_classes.cname IS 'Человекочитаемое наименование класса (Справочник, Документ, Счёт и т.д.)';
COMMENT ON COLUMN meta.entity_classes.mcomment IS 'Произвольное описание класса, его назначение и особенности';

CREATE TABLE meta.entity_composition (
    id integer NOT NULL,
    parent_entityid integer NOT NULL,
    child_entityid integer NOT NULL,
    role_id integer NOT NULL,
    c_link_fieldname character varying(63) NOT NULL,
    isortorder integer,
    from_template_id integer
);

COMMENT ON TABLE meta.entity_composition IS 'RealDictRow({'obj_description': 'Конфигурация связей «мастер-деталь» между типами сущностей. Определяет, какие сущности могут быть вложены в другие и с какой ролью.'})';
COMMENT ON COLUMN meta.entity_composition.id IS 'Первичный ключ';
COMMENT ON COLUMN meta.entity_composition.parent_entityid IS 'Тип сущности-мастера (ссылка на meta.entitytypes)';
COMMENT ON COLUMN meta.entity_composition.child_entityid IS 'Тип сущности-детали (ссылка на meta.entitytypes)';
COMMENT ON COLUMN meta.entity_composition.role_id IS 'Роль вложения (ссылка на meta.composition_roles)';
COMMENT ON COLUMN meta.entity_composition.c_link_fieldname IS 'Имя поля в ext-таблице детали, которое хранит ID родителя (например, invoiceid)';
COMMENT ON COLUMN meta.entity_composition.isortorder IS 'Порядок отображения вкладок в интерфейсе';
COMMENT ON COLUMN meta.entity_composition.from_template_id IS 'Если связь создана из шаблона класса — ссылка на meta.class_composition_templates(id). NULL = создана вручную.';

CREATE TABLE meta.entity_ref_rules (
    id integer NOT NULL,
    reftypeid integer NOT NULL,
    entitytypeid integer NOT NULL,
    role_source_entityid integer NOT NULL
);

COMMENT ON TABLE meta.entity_ref_rules IS 'RealDictRow({'obj_description': 'Правила участия сущностей в групповых связях. Определяет, какие типы сущностей могут быть участниками данного типа связи и из какого справочника брать роли.'})';
COMMENT ON COLUMN meta.entity_ref_rules.id IS 'Первичный ключ';
COMMENT ON COLUMN meta.entity_ref_rules.reftypeid IS 'Тип связи (ссылка на meta.entity_ref_types)';
COMMENT ON COLUMN meta.entity_ref_rules.entitytypeid IS 'Тип сущности-участника (ссылка на meta.entitytypes)';
COMMENT ON COLUMN meta.entity_ref_rules.role_source_entityid IS 'Тип сущности-справочника, откуда берутся роли для этого участника (например, «Семейные роли»)';

CREATE TABLE meta.entity_ref_types (
    id integer NOT NULL,
    cname character varying(255) NOT NULL,
    calias character varying(50) NOT NULL,
    mcomment text
);

COMMENT ON TABLE meta.entity_ref_types IS 'RealDictRow({'obj_description': 'Справочник типов групповых (коллективных) связей между сущностями. Например, «Семейные отношения», «Состав изделия», «Участники проекта».'})';
COMMENT ON COLUMN meta.entity_ref_types.id IS 'Первичный ключ';
COMMENT ON COLUMN meta.entity_ref_types.cname IS 'Человеческое название типа связи';
COMMENT ON COLUMN meta.entity_ref_types.calias IS 'Системный алиас типа связи (например, REF_FAMILY, REF_PROJECT)';
COMMENT ON COLUMN meta.entity_ref_types.mcomment IS 'Описание типа связи, его бизнес-смысл';

CREATE TABLE meta.entitytype_bu_access (
    entitytype_id integer NOT NULL,
    balanceunit_id integer NOT NULL,
    is_active boolean NOT NULL
);

COMMENT ON TABLE meta.entitytype_bu_access IS 'RealDictRow({'obj_description': 'Какие типы документов доступны в каких БЕ'})';

CREATE TABLE meta.entitytype_visibility (
    id integer NOT NULL,
    entitytype_id integer NOT NULL,
    balanceunit_id integer NOT NULL,
    visibility_policy character(1) NOT NULL
);

COMMENT ON TABLE meta.entitytype_visibility IS 'RealDictRow({'obj_description': 'Политика видимости типа сущности в балансовой единице'})';
COMMENT ON COLUMN meta.entitytype_visibility.entitytype_id IS 'Тип сущности';
COMMENT ON COLUMN meta.entitytype_visibility.balanceunit_id IS 'Балансовая единица';
COMMENT ON COLUMN meta.entitytype_visibility.visibility_policy IS 'Политика: I - индивидуальная (проверка entity_visibility), A - все экземпляры видны, N - все экземпляры не видны';

CREATE TABLE meta.entitytypes (
    id integer NOT NULL,
    cname character varying(255) NOT NULL,
    calias character varying(50) NOT NULL,
    cbaseclass character varying(20) NOT NULL,
    lisdependent boolean,
    lishierarchy boolean,
    lisversioned boolean,
    isecuritystrategy integer,
    class_id integer,
    mcomment text,
    status_id integer,
    is_system boolean NOT NULL
);

COMMENT ON TABLE meta.entitytypes IS 'RealDictRow({'obj_description': 'Реестр типов сущностей системы Mozart. Здесь задаются «чертежи» объектов: будет это справочник, документ, счёт и т.д.'})';
COMMENT ON COLUMN meta.entitytypes.id IS 'Первичный ключ, уникальный идентификатор типа сущности';
COMMENT ON COLUMN meta.entitytypes.cname IS 'Человеческое название типа сущности (например, «Персона», «Накладная»)';
COMMENT ON COLUMN meta.entitytypes.calias IS 'Системный алиас для SQL-запросов (например, PERSON, INVOICE)';
COMMENT ON COLUMN meta.entitytypes.cbaseclass IS 'Базовый класс поведения: Document, Dictionary, Account и т.п.';
COMMENT ON COLUMN meta.entitytypes.lisdependent IS 'Флаг зависимости: true – если сущность не существует без родителя (например, строка документа)';
COMMENT ON COLUMN meta.entitytypes.lishierarchy IS 'Флаг иерархичности: true – если справочник поддерживает древовидную структуру (папки/группы)';
COMMENT ON COLUMN meta.entitytypes.lisversioned IS 'Флаг версионности: true – если объекты этого типа хранят историю изменений (Машина времени)';
COMMENT ON COLUMN meta.entitytypes.isecuritystrategy IS 'Стратегия безопасности: 0 – нет, 1 – на таблицу, 2 – на каждую запись';
COMMENT ON COLUMN meta.entitytypes.class_id IS 'Ссылка на класс сущности (из meta.entity_classes), определяющий поведение объекта';
COMMENT ON COLUMN meta.entitytypes.mcomment IS 'Описание типа сущности (назначение, особенности)';
COMMENT ON COLUMN meta.entitytypes.status_id IS 'Текущий статус типа сущности';
COMMENT ON COLUMN meta.entitytypes.is_system IS 'Системная сущность (не может быть удалена или переименована через конфигуратор)';

CREATE TABLE meta.field_types (
    ccode character(1) NOT NULL,
    cname character varying(50) NOT NULL,
    mcomment text
);

COMMENT ON TABLE meta.field_types IS 'RealDictRow({'obj_description': 'Словарь-дешифратор системных типов данных'})';

CREATE TABLE meta.fields (
    id integer NOT NULL,
    entitytypeid integer,
    cfieldname character varying(63) NOT NULL,
    calias character varying(100) NOT NULL,
    cfieldtype character(1) NOT NULL,
    lisrequired boolean,
    lisindexed boolean,
    nlength integer,
    ndecimals integer,
    isortorder integer,
    ref_entitytypeid integer,
    mcomment text,
    status_id integer,
    is_system boolean
);

COMMENT ON TABLE meta.fields IS 'RealDictRow({'obj_description': 'Реестр полей расширения для сущностей. Определяет атрибуты, которые хранятся в ext-таблицах.'})';
COMMENT ON COLUMN meta.fields.id IS 'Первичный ключ';
COMMENT ON COLUMN meta.fields.entitytypeid IS 'Ссылка на тип сущности (meta.entitytypes), которой принадлежит поле';
COMMENT ON COLUMN meta.fields.cfieldname IS 'Физическое имя поля в таблице расширения (SQL-идентификатор)';
COMMENT ON COLUMN meta.fields.calias IS 'Бизнес-имя поля (отображается в интерфейсе)';
COMMENT ON COLUMN meta.fields.cfieldtype IS 'Тип данных по венгерской нотации: C-строка, N-число, I-целое, D-дата, T-дата/время, L-логика, M-мемо, R-ссылка, G-картинка, V-видео, F-файл, J-jsonb, A-массив';
COMMENT ON COLUMN meta.fields.lisrequired IS 'Обязательность заполнения (NOT NULL)';
COMMENT ON COLUMN meta.fields.lisindexed IS 'Создавать ли индекс по этому полю в ext-таблице';
COMMENT ON COLUMN meta.fields.nlength IS 'Максимальная длина (для строк) или точность (для чисел)';
COMMENT ON COLUMN meta.fields.ndecimals IS 'Количество знаков после запятой (для чисел)';
COMMENT ON COLUMN meta.fields.isortorder IS 'Порядок отображения поля в формах и гридах';
COMMENT ON COLUMN meta.fields.ref_entitytypeid IS 'Для полей типа R (ссылка) указывает, на какой тип сущности ссылаемся';
COMMENT ON COLUMN meta.fields.mcomment IS 'Описание поля, пояснение его смысла';
COMMENT ON COLUMN meta.fields.status_id IS 'Текущий статус поля';
COMMENT ON COLUMN meta.fields.is_system IS 'Служебное поле (sourceid, data_hash)';

CREATE TABLE meta.form_elements (
