COMMENT ON TABLE meta.form_elements IS 'RealDictRow({'obj_description': 'Содержимое форм: элементы управления, из которых строятся динамические интерфейсы. Хранит иерархию компонентов формы.'})';
COMMENT ON COLUMN meta.form_elements.id IS 'Первичный ключ';
COMMENT ON COLUMN meta.form_elements.formid IS 'Ссылка на форму (meta.forms), которой принадлежит элемент';
COMMENT ON COLUMN meta.form_elements.parentid IS 'Ссылка на родительский элемент (для иерархических компоновок)';
COMMENT ON COLUMN meta.form_elements.calias IS 'Системный алиас элемента (уникальный в пределах формы)';
COMMENT ON COLUMN meta.form_elements.cclass IS 'Класс элемента (например, "field", "grid", "panel")';
COMMENT ON COLUMN meta.form_elements.itaborder IS 'Порядок обхода при нажатии Tab';
COMMENT ON COLUMN meta.form_elements.cdatasource IS 'Источник данных для элемента (например, имя сущности или запрос)';
COMMENT ON COLUMN meta.form_elements.mproperties_json IS 'Дополнительные свойства элемента в формате JSON';
COMMENT ON COLUMN meta.form_elements.isortorder IS 'Порядок сортировки (0-999)';
COMMENT ON COLUMN meta.form_elements.lisactive IS 'Элемент активен (если FALSE — не отображается)';

CREATE TABLE meta.forms (
    id integer NOT NULL,
