COMMENT ON TABLE meta.forms IS 'RealDictRow({'obj_description': 'Справочник форм (экранов) системы. Каждая форма привязана к определённой сущности (entitytype) и определяет представление данных.'})';
COMMENT ON COLUMN meta.forms.id IS 'Первичный ключ';
COMMENT ON COLUMN meta.forms.ientitytypeid IS 'Тип сущности (meta.entitytypes), для которой предназначена форма (якорная сущность)';
COMMENT ON COLUMN meta.forms.calias IS 'Системный алиас формы (уникальный)';
COMMENT ON COLUMN meta.forms.cname IS 'Человеческое название формы';
COMMENT ON COLUMN meta.forms.mstate_json IS 'JSON-описание состояния формы (например, настройки видимости, раскладка)';

