COMMENT ON COLUMN meta.import_sources.last_import IS 'Дата и время последнего импорта';
COMMENT ON COLUMN meta.import_sources.created_at IS 'Дата создания записи';
COMMENT ON COLUMN meta.import_sources.updated_at IS 'Дата последнего обновления';

CREATE TABLE meta.import_target_entities (
    id integer NOT NULL,
    profile_id integer NOT NULL,
    entity_id integer NOT NULL,
    entity_name character varying(255) NOT NULL
);

COMMENT ON TABLE meta.import_target_entities IS 'RealDictRow({'obj_description': None})';

CREATE TABLE meta.menu (
    id integer NOT NULL,
    roleid integer,
    parentid integer,
    cname character varying(100) NOT NULL,
    calias character varying(50),
    ientitytypeid integer,
    isortorder integer,
    iformid integer,
    lisactive boolean,
    oicon bytea,
    cicon_type character varying(10),
    copentype character varying(20),
    openparams_json jsonb
);

COMMENT ON TABLE meta.menu IS 'RealDictRow({'obj_description': 'Иерархический справочник пунктов меню. Каждый пункт может быть привязан к роли (интерфейсной роли) и к типу сущности для навигации.'})';
COMMENT ON COLUMN meta.menu.id IS 'Первичный ключ';
COMMENT ON COLUMN meta.menu.roleid IS 'Ссылка на роль (auth.roles), для которой доступен пункт меню. Пользователь входит ровно в одну роль из группы «Интерфейсные роли».';
COMMENT ON COLUMN meta.menu.parentid IS 'Ссылка на родительский пункт меню (для иерархии)';
COMMENT ON COLUMN meta.menu.cname IS 'Текст пункта меню, отображаемый пользователю';
COMMENT ON COLUMN meta.menu.calias IS 'Системный алиас пункта меню (для программной навигации)';
COMMENT ON COLUMN meta.menu.ientitytypeid IS 'Тип сущности (дубль из формы) — для быстрой фильтрации';
COMMENT ON COLUMN meta.menu.isortorder IS 'Порядок сортировки (0-999)';
COMMENT ON COLUMN meta.menu.iformid IS 'Ссылка на форму (meta.forms.id) — основной способ навигации';
COMMENT ON COLUMN meta.menu.lisactive IS 'Пункт меню активен (если FALSE — скрыт)';
COMMENT ON COLUMN meta.menu.oicon IS 'Иконка пункта меню (PNG/SVG/ICO) в байтовом виде';
COMMENT ON COLUMN meta.menu.cicon_type IS 'Тип иконки: png, svg, ico';
COMMENT ON COLUMN meta.menu.copentype IS 'Где открывать: main (основная область), tab (новая вкладка), dialog (диалог)';
COMMENT ON COLUMN meta.menu.openparams_json IS 'Дополнительные параметры открытия (фильтры, режим и т.д.)';

CREATE TABLE meta.object_statuses (
    id integer NOT NULL,
    code character varying(20) NOT NULL,
    name character varying(50) NOT NULL,
    description text
);

COMMENT ON TABLE meta.object_statuses IS 'RealDictRow({'obj_description': 'Статусы жизненного цикла мета-объектов'})';
COMMENT ON COLUMN meta.object_statuses.code IS 'Код статуса: DEV, PROD';
COMMENT ON COLUMN meta.object_statuses.name IS 'Отображаемое имя';
COMMENT ON COLUMN meta.object_statuses.description IS 'Описание';

CREATE TABLE meta.register_dimensions (
    id integer NOT NULL,
    register_id integer NOT NULL,
    dimension_order integer NOT NULL,
    entitytype_id integer NOT NULL,
    is_required boolean
);

COMMENT ON TABLE meta.register_dimensions IS 'RealDictRow({'obj_description': 'Измерения (аналитика) регистра – набор сущностей, по которым ведётся учёт'})';
COMMENT ON COLUMN meta.register_dimensions.id IS 'Первичный ключ';
COMMENT ON COLUMN meta.register_dimensions.register_id IS 'Ссылка на регистр';
COMMENT ON COLUMN meta.register_dimensions.dimension_order IS 'Порядок измерения (важен для группировок)';
COMMENT ON COLUMN meta.register_dimensions.entitytype_id IS 'Тип сущности, выступающей в роли измерения (счёт, ипостась, оргструктура и т.п.)';
COMMENT ON COLUMN meta.register_dimensions.is_required IS 'Обязательность указания данного измерения при записи движений';

CREATE TABLE meta.register_resources (
    id integer NOT NULL,
    register_id integer NOT NULL,
    calias character varying(50) NOT NULL,
    cname character varying(255) NOT NULL,
    resource_type character(1) NOT NULL,
    aspect_entitytype_id integer
);

COMMENT ON TABLE meta.register_resources IS 'RealDictRow({'obj_description': 'Ресурсы (числовые показатели) регистра, например "дебет", "кредит", "количество"'})';
COMMENT ON COLUMN meta.register_resources.id IS 'Первичный ключ';
COMMENT ON COLUMN meta.register_resources.register_id IS 'Ссылка на регистр';
COMMENT ON COLUMN meta.register_resources.calias IS 'Код ресурса (например, DEBET, CREDIT, QTY)';
COMMENT ON COLUMN meta.register_resources.cname IS 'Наименование ресурса';
COMMENT ON COLUMN meta.register_resources.resource_type IS 'Тип ресурса: S - сумма, Q - количество, A - сумма в валюте';
COMMENT ON COLUMN meta.register_resources.aspect_entitytype_id IS 'Если ресурс привязан к конкретной ипостаси, указывается тип ипостаси';

CREATE TABLE meta.registers (
    id integer NOT NULL,
    calias character varying(50) NOT NULL,
    cname character varying(255) NOT NULL,
    ctype character(1) NOT NULL,
    periodicity character(1) NOT NULL,
    is_active boolean
);

COMMENT ON TABLE meta.registers IS 'RealDictRow({'obj_description': 'Реестр регистров учёта (обороты и остатки)'})';
COMMENT ON COLUMN meta.registers.id IS 'Первичный ключ';
COMMENT ON COLUMN meta.registers.calias IS 'Системный алиас регистра (например, "INVENTORY", "SALES")';
COMMENT ON COLUMN meta.registers.cname IS 'Наименование регистра';
COMMENT ON COLUMN meta.registers.ctype IS 'Тип регистра: B - остаточный (балансовый), T - оборотный (накопительный)';
COMMENT ON COLUMN meta.registers.periodicity IS 'Периодичность: D - день, M - месяц, Q - квартал, Y - год';
COMMENT ON COLUMN meta.registers.is_active IS 'Флаг активности: true - регистр используется, false - отключён';

CREATE TABLE meta.route_step_templates (
    id integer NOT NULL,
    route_template_id integer NOT NULL,
    parent_step_id integer,
    step_order integer NOT NULL,
    step_name character varying(255) NOT NULL,
    assign_type character varying(20) NOT NULL,
    assign_target character varying(255),
    is_optional boolean NOT NULL,
    time_limit_days integer,
    scope character varying(20),
    scope_target character varying(255),
    next_step_on_reject integer,
    notify_on_assign boolean NOT NULL,
    sort_order integer NOT NULL,
    mcomment text
);

COMMENT ON TABLE meta.route_step_templates IS 'RealDictRow({'obj_description': 'Шаблоны этапов маршрута'})';

CREATE TABLE meta.route_template_bu_access (
    route_template_id integer NOT NULL,
    balanceunit_id integer NOT NULL,
    is_active boolean NOT NULL
);

COMMENT ON TABLE meta.route_template_bu_access IS 'RealDictRow({'obj_description': 'Какие шаблоны доступны в каких БЕ'})';

CREATE TABLE meta.route_templates (
    id integer NOT NULL,
    calias character varying(100) NOT NULL,
    cname character varying(500) NOT NULL,
    is_active boolean NOT NULL,
    mcomment text,
    created_at timestamp with time zone NOT NULL
);

COMMENT ON TABLE meta.route_templates IS 'RealDictRow({'obj_description': 'Шаблоны маршрутов движения документов'})';

CREATE TABLE meta.sys_params (
    id integer NOT NULL,
    calias character varying(50) NOT NULL,
    cname character varying(255),
    ctype character(1) NOT NULL,
    isystem boolean,
    mdefault_value text
);

COMMENT ON TABLE meta.sys_params IS 'RealDictRow({'obj_description': 'Реестр глобальных переменных сессии (g-переменные). Используются для хранения настроек, контекста выполнения и т.п.'})';
COMMENT ON COLUMN meta.sys_params.id IS 'Первичный ключ';
COMMENT ON COLUMN meta.sys_params.calias IS 'Системный алиас параметра (например, CURRENT_USER_ID, DEFAULT_CURRENCY)';
COMMENT ON COLUMN meta.sys_params.cname IS 'Человеческое название параметра';
COMMENT ON COLUMN meta.sys_params.ctype IS 'Тип данных параметра: C-строка, N-число, D-дата, L-логика и т.д. (аналогично полям)';
COMMENT ON COLUMN meta.sys_params.isystem IS 'Признак системного параметра (не может быть удалён или изменён пользователем)';
COMMENT ON COLUMN meta.sys_params.mdefault_value IS 'Значение по умолчанию (в текстовом представлении)';

CREATE TABLE meta.system_entity_roles (
    id integer NOT NULL,
    entitytype_id integer NOT NULL,
    balanceunit_id integer,
    role_code character varying(50) NOT NULL,
    is_active boolean NOT NULL,
    mcomment text
);

COMMENT ON TABLE meta.system_entity_roles IS 'RealDictRow({'obj_description': 'Жёсткая привязка системных ролей к типам сущностей в разрезе БЕ'})';

