("CREATE OR REPLACE FUNCTION public.pgp_sym_decrypt(bytea, text)\n RETURNS text\n LANGUAGE c\n IMMUTABLE PARALLEL SAFE STRICT\nAS '$libdir/pgcrypto', $function$pgp_sym_decrypt_text$function$\n",)

("CREATE OR REPLACE FUNCTION public.pgp_sym_decrypt(bytea, text)\n RETURNS text\n LANGUAGE c\n IMMUTABLE PARALLEL SAFE STRICT\nAS '$libdir/pgcrypto', $function$pgp_sym_decrypt_text$function$\n",)

("CREATE OR REPLACE FUNCTION public.pgp_sym_decrypt_bytea(bytea, text)\n RETURNS bytea\n LANGUAGE c\n IMMUTABLE PARALLEL SAFE STRICT\nAS '$libdir/pgcrypto', $function$pgp_sym_decrypt_bytea$function$\n",)

("CREATE OR REPLACE FUNCTION public.pgp_sym_decrypt_bytea(bytea, text)\n RETURNS bytea\n LANGUAGE c\n IMMUTABLE PARALLEL SAFE STRICT\nAS '$libdir/pgcrypto', $function$pgp_sym_decrypt_bytea$function$\n",)

("CREATE OR REPLACE FUNCTION public.pgp_sym_encrypt(text, text)\n RETURNS bytea\n LANGUAGE c\n PARALLEL SAFE STRICT\nAS '$libdir/pgcrypto', $function$pgp_sym_encrypt_text$function$\n",)

("CREATE OR REPLACE FUNCTION public.pgp_sym_encrypt(text, text)\n RETURNS bytea\n LANGUAGE c\n PARALLEL SAFE STRICT\nAS '$libdir/pgcrypto', $function$pgp_sym_encrypt_text$function$\n",)

("CREATE OR REPLACE FUNCTION public.pgp_sym_encrypt_bytea(bytea, text)\n RETURNS bytea\n LANGUAGE c\n PARALLEL SAFE STRICT\nAS '$libdir/pgcrypto', $function$pgp_sym_encrypt_bytea$function$\n",)

("CREATE OR REPLACE FUNCTION public.pgp_sym_encrypt_bytea(bytea, text)\n RETURNS bytea\n LANGUAGE c\n PARALLEL SAFE STRICT\nAS '$libdir/pgcrypto', $function$pgp_sym_encrypt_bytea$function$\n",)

("CREATE OR REPLACE FUNCTION public.sync_ext_comments(p_entitytypeid integer DEFAULT NULL::integer)\n RETURNS void\n LANGUAGE plpgsql\nAS $function$\nDECLARE\n    rec RECORD;\n    v_comment TEXT;\nBEGIN\n    FOR rec IN (\n        SELECT \n            f.entitytypeid,\n            f.cfieldname,\n            f.calias,\n            e.calias AS entity_alias\n        FROM meta.fields f\n        JOIN meta.entitytypes e ON e.id = f.entitytypeid\n        WHERE (p_entitytypeid IS NULL OR f.entitytypeid = p_entitytypeid)\n    ) LOOP\n        -- Формируем комментарий: бизнес-имя + доп. информация\n        v_comment := format('Поле: %s (системное имя: %s)', rec.calias, rec.cfieldname);\n        -- Добавляем информацию о ссылке, если есть\n        -- (можно расширить)\n        \n        -- Выполняем COMMENT\n        EXECUTE format('COMMENT ON COLUMN ext.%I.%I IS %L',\n                       'ext_' || lower(rec.entity_alias),\n                       rec.cfieldname,\n                       v_comment);\n    END LOOP;\nEND;\n$function$\n",)

-- ==========================================
-- СХЕМА: sys
-- ==========================================

CREATE TABLE sys.active_locks (
    id integer NOT NULL,
    instanceid integer NOT NULL,
    userid integer NOT NULL,
    balanceunitid integer NOT NULL,
    t_locktime timestamp without time zone,
    c_locktype character varying(20)
);

COMMENT ON TABLE sys.active_locks IS 'RealDictRow({'obj_description': 'Реестр пессимистических блокировок (Root Lock)'})';

CREATE TABLE sys.audit_log (
    id integer NOT NULL,
    t_timestamp timestamp without time zone,
    i_userid integer,
    i_instanceid integer,
    c_fieldname character varying(63),
    m_old_buffer text,
    m_new_value text
);

COMMENT ON TABLE sys.audit_log IS 'RealDictRow({'obj_description': None})';

("CREATE OR REPLACE PROCEDURE sys.p_clear_expired_locks(IN p_n_timeout_minutes integer DEFAULT 30)\n LANGUAGE plpgsql\nAS $procedure$\nDECLARE\n    v_n_deleted integer;\nBEGIN\n    -- Удаляем все блокировки, которые старше указанного времени (Раздел 7.5)\n    DELETE FROM sys.active_locks \n    WHERE t_locktime < (now() - (p_n_timeout_minutes || ' minutes')::interval);\n    \n    GET DIAGNOSTICS v_n_deleted = ROW_COUNT;\n    \n    -- Если что-то удалили, пишем в системный лог (Раздел 9.2)\n    IF v_n_deleted > 0 THEN\n        INSERT INTO sys.event_log (c_eventsource, c_actionalias, l_success)\n        VALUES ('LOCK_MANAGER', 'AUTO_UNLOCK_EXPIRED', true);\n    END IF;\nEND;\n$procedure$\n",)

("CREATE OR REPLACE PROCEDURE sys.p_setlock(IN p_i_instanceid integer, IN p_i_userid integer, IN p_i_balanceunitid integer)\n LANGUAGE plpgsql\nAS $procedure$\nBEGIN\n    -- 1. Сначала чистим старье (Раздел 7.5)\n    CALL sys.p_clear_expired_locks(30);\n\n    -- 2. Пытаемся поставить свой замок\n    -- Используем INSERT ... ON CONFLICT для атомарности\n    INSERT INTO sys.active_locks (instanceid, userid, balanceunitid, t_locktime)\n    VALUES (p_i_instanceid, p_i_userid, p_i_balanceunitid, now())\n    ON CONFLICT (instanceid) DO UPDATE \n    SET \n        -- Если мы сами - продлеваем\n        t_locktime = CASE WHEN sys.active_locks.userid = EXCLUDED.userid THEN EXCLUDED.t_locktime ELSE sys.active_locks.t_locktime END\n    WHERE sys.active_locks.userid = EXCLUDED.userid;\n\n    -- 3. Если вставить не удалось (уже занято кем-то другим и не протухло)\n    IF NOT EXISTS (SELECT 1 FROM sys.active_locks WHERE instanceid = p_i_instanceid AND userid = p_i_userid) THEN\n        DECLARE\n            v_i_locker integer;\n        BEGIN\n            SELECT userid INTO v_i_locker FROM sys.active_locks WHERE instanceid = p_i_instanceid;\n            RAISE EXCEPTION 'Объект заблокирован пользователем ID % менее 30 минут назад.', v_i_locker;\n        END;\n    END IF;\nEND;\n$procedure$\n",)

('CREATE OR REPLACE PROCEDURE sys.p_writeaudit(IN p_i_userid integer, IN p_i_instanceid integer, IN p_c_fieldname character varying, IN p_m_old_value text, IN p_m_new_value text)\n LANGUAGE plpgsql\nAS $procedure$\nBEGIN\n    -- Пишем в лог только если значения реально различаются (Раздел 9.1)\n    IF p_m_old_value IS DISTINCT FROM p_m_new_value THEN\n        INSERT INTO sys.audit_log (i_userid, i_instanceid, c_fieldname, m_old_buffer, m_new_value)\n        VALUES (p_i_userid, p_i_instanceid, p_c_fieldname, p_m_old_value, p_m_new_value);\n    END IF;\nEND;\n$procedure$\n',)

